input.command:
echo "=== Best per branch ===" && awk -F'\t' 'NR>1 && $5!="crash" {
  mean=$4+0; resid=$2+0;
  if (mean > 0.5) branch="positive"
  else if (mean < -0.5) branch="negative"
  else if ($3+0 > 0.03) branch="small_osc"
  else branch="trivial"
  if (!(branch in best) || resid < best[branch]) { best[branch]=resid; exp[branch]=$1; desc[branch]=$6 }
}
END { for (b in best) printf "%s: %s residual=%.2e (%s)\n", b, exp[b], best[b], desc[b] }' results.tsv

